 using System.ComponentModel;
 using System.Text;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";
 var topic = args.Length > 0 ? string.Join(' ', args) : "recent advances in quantum computing";

 // --- Tools ---
 var tools = new ResearchTools();
 var aiTools = new AITool[]
 {
     AIFunctionFactory.Create(tools.SearchWeb),
     AIFunctionFactory.Create(tools.TakeNote),
     AIFunctionFactory.Create(tools.GetNotes),
 };

 // --- Chat client with function-invocation middleware ---
 var innerClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 var chatClient = new ChatClientBuilder(innerClient)
     .UseFunctionInvocation(configure: fic =>
     {
         fic.MaximumIterationsPerRequest = 10;
         fic.IncludeDetailedErrors = true;
     })
     .Build();

 // --- Build the agent ---
 var agent = new ChatClientBuilder(chatClient)
     .BuildAIAgent(
         instructions: """
             You are a research agent. Your goal is to thoroughly research a given topic.

             Workflow:
             1. Search the web for information on the topic using the SearchWeb tool.
             2. Take notes on key findings using the TakeNote tool.
             3. Perform additional searches to fill gaps or explore sub-topics.
             4. After gathering enough material, call GetNotes to review your notes.
             5. Produce a well-structured final summary with source references.

             Your final message must be the summary. Do NOT call any tools in your
             final response.
             """,
         name: "ResearchAgent",
         description: "An agent that researches topics by searching the web and taking notes.",
         tools: aiTools);

 // --- Run the agent ---
 Console.ForegroundColor = ConsoleColor.Cyan;
 Console.WriteLine($"🔍 Research Agent — investigating: \"{topic}\"\n");
 Console.ResetColor();

 var session = await agent.CreateSessionAsync("research-1");

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session))
 {
     if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
     {
         Console.Write(update.Text);
     }
 }

 Console.WriteLine();

 var notes = tools.GetAllNotes();
 if (notes.Count > 0)
 {
     Console.ForegroundColor = ConsoleColor.DarkYellow;
     Console.WriteLine($"\n📝 Agent collected {notes.Count} note(s) during research.");
     Console.ResetColor();
 }

 // ========================================================================
 // Tools
 // ========================================================================
 sealed class ResearchTools
 {
     private readonly List<string> _notes = [];
     private readonly HttpClient _http = new();

     [Description("Searches the web for a query and returns result snippets with titles and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query to look up on the web.")] string query)
     {
         Console.ForegroundColor = ConsoleColor.DarkGray;
         Console.WriteLine($"  🌐 Searching: \"{query}\"");
         Console.ResetColor();

         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
             _http.DefaultRequestHeaders.UserAgent.Clear();
             _http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
             var json = await _http.GetStringAsync(url);

             var doc = System.Text.Json.JsonDocument.Parse(json);
             var root = doc.RootElement;
             var sb = new StringBuilder();

             var abstractText = root.GetProperty("AbstractText").GetString();
             var abstractSource = root.GetProperty("AbstractSource").GetString();
             var abstractUrl = root.GetProperty("AbstractURL").GetString();
             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 sb.AppendLine($"## Main Result ({abstractSource})");
                 sb.AppendLine(abstractText);
                 sb.AppendLine($"Source: {abstractUrl}");
                 sb.AppendLine();
             }

             if (root.TryGetProperty("RelatedTopics", out var topics))
             {
                 var count = 0;
                 foreach (var t in topics.EnumerateArray())
                 {
                     if (count >= 8) break;
                     var text = t.TryGetProperty("Text", out var tp) ? tp.GetString() : null;
                     var link = t.TryGetProperty("FirstURL", out var fu) ? fu.GetString() : null;
                     if (!string.IsNullOrWhiteSpace(text))
                     {
                         sb.AppendLine($"- {text}");
                         if (!string.IsNullOrEmpty(link))
                             sb.AppendLine($"  URL: {link}");
                         count++;
                     }
                 }
             }

             return sb.Length > 0
                 ? sb.ToString()
                 : "No results found. Try rephrasing your query or searching for a more specific sub-topic.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     [Description("Saves a research note to record key findings, facts, or quotes during research.")]
     public string TakeNote(
         [Description("A concise research note capturing a key finding.")] string note,
         [Description("The source URL or name where this information was found.")] string source = "unknown")
     {
         var entry = $"[{_notes.Count + 1}] {note} (source: {source})";
         _notes.Add(entry);

         Console.ForegroundColor = ConsoleColor.DarkGray;
         Console.WriteLine($"  📝 Note #{_notes.Count}: {Truncate(note, 80)}");
         Console.ResetColor();

         return $"Note saved (#{_notes.Count}).";
     }

     [Description("Retrieves all research notes collected so far. Call this before writing the final summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0) return "No notes saved yet.";
         return string.Join("\n", _notes);
     }

     public List<string> GetAllNotes() => _notes;

     private static string Truncate(string s, int max) =>
         s.Length <= max ? s : string.Concat(s.AsSpan(0, max), "...");
 }
